import { useState, useEffect } from 'react';
import { useParams, useNavigate, useSearchParams } from 'react-router-dom';
import { ArrowLeft, ExternalLink, Heart, Share2, TrendingUp, AlertCircle, Loader } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import DashboardLayout from '@/components/dashboard/DashboardLayout';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { trpc } from '@/lib/trpc';
import { useAuth } from '@/contexts/AuthContext';

interface PriceHistoryPoint {
  date: string;
  price: number;
}

interface Deal {
  dealId: string;
  marketplace: string;
  title: string;
  buyPrice: number;
  sellPrice: number;
  flipScore: number;
  profitMargin: number;
  qualityScore: number;
  condition: 'new' | 'like-new' | 'good' | 'fair' | 'poor';
  sellerName: string;
  sellerRating: number;
  marketplaceUrl: string;
  imageUrl?: string;
  images: string[];
  createdAt: Date;
  expiresAt: Date;
  description: string;
  category: string;
  priceHistory: PriceHistoryPoint[];
  flagged: boolean;
  flagReason?: string;
}

export default function DealDetail() {
  const { dealId } = useParams<{ dealId: string }>();
  const [searchParams] = useSearchParams();
  const marketplace = searchParams.get('marketplace') || 'unknown';
  const navigate = useNavigate();
  const { user } = useAuth();

  const [isSaved, setIsSaved] = useState(false);
  const [fees, setFees] = useState(15); // Default 15% fees
  const [error, setError] = useState<string | null>(null);

  // tRPC hooks
  const dealQuery = trpc.deals.getDetail.useQuery(
    { dealId: dealId || '', marketplace },
    { enabled: !!dealId }
  );

  const saveDealMutation = trpc.deals.saveDeal.useMutation();

  const deal = dealQuery.data as Deal | undefined;

  const handleSaveDeal = async () => {
    if (!dealId) return;

    try {
      await saveDealMutation.mutateAsync({
        dealId,
        marketplace,
      });
      setIsSaved(true);
      // Show success message
      setTimeout(() => {
        setError(null);
      }, 3000);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to save deal');
    }
  };

  const getConditionColor = (condition: string) => {
    switch (condition) {
      case 'new':
        return 'bg-[#10B981]/20 text-[#6EE7B7]';
      case 'like-new':
        return 'bg-[#10B981]/20 text-[#6EE7B7]';
      case 'good':
        return 'bg-[#06B6D4]/20 text-[#22D3EE]';
      case 'fair':
        return 'bg-[#F59E0B]/20 text-[#FCD34D]';
      case 'poor':
        return 'bg-red-500/20 text-red-300';
      default:
        return 'bg-[#6B7280]/20 text-[#D1D5DB]';
    }
  };

  if (dealQuery.isLoading) {
    return (
      <DashboardLayout currentPage="search" userTier={user?.tier || 'free'}>
        <div className="flex items-center justify-center min-h-screen">
          <div className="text-center">
            <Loader size={48} className="mx-auto text-blue-400 mb-4 animate-spin" />
            <h3 className="text-xl font-semibold text-slate-900">Loading Deal Details</h3>
          </div>
        </div>
      </DashboardLayout>
    );
  }

  if (dealQuery.isError || !deal) {
    return (
      <DashboardLayout currentPage="search" userTier={user?.tier || 'free'}>
        <div className="max-w-4xl mx-auto">
          <div className="flex items-center gap-4 mb-6">
            <button
              onClick={() => navigate(-1)}
              className="p-2 hover:bg-slate-100 rounded-lg transition"
            >
              <ArrowLeft size={24} className="text-slate-600" />
            </button>
            <h1 className="text-3xl font-bold text-slate-900">Deal Details</h1>
          </div>

          <Card className="p-12 text-center">
            <AlertCircle size={48} className="mx-auto text-red-400 mb-4" />
            <h3 className="text-xl font-semibold text-slate-900 mb-2">Deal Not Found</h3>
            <p className="text-slate-600 mb-6">The deal you're looking for could not be found.</p>
            <Button
              onClick={() => navigate(-1)}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg"
            >
              Go Back
            </Button>
          </Card>
        </div>
      </DashboardLayout>
    );
  }

  // Profit calculator
  const netProfit = deal.sellPrice - deal.buyPrice - (deal.sellPrice * fees) / 100;
  const netMargin = ((netProfit / deal.buyPrice) * 100).toFixed(1);

  return (
    <DashboardLayout currentPage="search" userTier={user?.tier || 'free'}>
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="flex items-center gap-4 mb-6">
          <button
            onClick={() => navigate(-1)}
            className="p-2 hover:bg-slate-100 rounded-lg transition"
          >
            <ArrowLeft size={24} className="text-slate-600" />
          </button>
          <h1 className="text-3xl font-bold text-slate-900">Deal Details</h1>
        </div>

        {/* Error Message */}
        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3">
            <AlertCircle size={20} className="text-red-600 flex-shrink-0 mt-0.5" />
            <p className="text-red-900">{error}</p>
          </div>
        )}

        {/* Flagged Warning */}
        {deal.flagged && (
          <div className="mb-6 p-4 bg-yellow-50 border border-yellow-200 rounded-lg flex items-start gap-3">
            <AlertCircle size={20} className="text-yellow-600 flex-shrink-0 mt-0.5" />
            <div>
              <p className="font-medium text-yellow-900">Deal Flagged</p>
              <p className="text-sm text-yellow-800">{deal.flagReason || 'This deal has been flagged for review'}</p>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Main Content */}
          <div className="lg:col-span-2 space-y-6">
            {/* Deal Header Card */}
            <Card className="p-6">
              <div className="flex items-start justify-between mb-4">
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <span className="px-3 py-1 bg-blue-100 text-blue-800 rounded-full text-sm font-medium">
                      {deal.marketplace}
                    </span>
                    <span className={`px-3 py-1 rounded-full text-sm font-medium ${getConditionColor(deal.condition)}`}>
                      {deal.condition.charAt(0).toUpperCase() + deal.condition.slice(1)}
                    </span>
                    {deal.category && (
                      <span className="px-3 py-1 bg-purple-100 text-purple-800 rounded-full text-sm font-medium">
                        {deal.category}
                      </span>
                    )}
                  </div>
                  <h2 className="text-2xl font-bold text-slate-900 mb-2">{deal.title}</h2>
                  <p className="text-slate-600">
                    Listed {new Date(deal.createdAt).toLocaleDateString()} • 
                    Expires {new Date(deal.expiresAt).toLocaleDateString()}
                  </p>
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() => setIsSaved(!isSaved)}
                    className={`p-3 rounded-lg transition ${
                      isSaved
                        ? 'bg-red-100 text-red-600'
                        : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                    }`}
                  >
                    <Heart size={20} fill={isSaved ? 'currentColor' : 'none'} />
                  </button>
                  <button className="p-3 bg-slate-100 text-slate-600 hover:bg-slate-200 rounded-lg transition">
                    <Share2 size={20} />
                  </button>
                </div>
              </div>

              {/* Image */}
              <div className="mb-6 rounded-lg overflow-hidden bg-slate-100 h-64">
                {deal.imageUrl ? (
                  <img
                    src={deal.imageUrl}
                    alt={deal.title}
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-slate-400">
                    No Image Available
                  </div>
                )}
              </div>

              {/* Description */}
              <div className="mb-6">
                <h3 className="text-lg font-semibold text-slate-900 mb-2">Description</h3>
                <p className="text-slate-600 leading-relaxed">{deal.description}</p>
              </div>

              {/* Seller Info */}
              <div className="p-4 bg-slate-50 rounded-lg">
                <h3 className="text-lg font-semibold text-slate-900 mb-3">Seller Information</h3>
                <div className="flex items-center justify-between">
                  <div>
                    <p className="font-medium text-slate-900">{deal.sellerName}</p>
                    <div className="flex items-center gap-1 mt-1">
                      <span className="text-yellow-500">★</span>
                      <span className="text-slate-600">{(deal.sellerRating / 20).toFixed(1)}/5.0</span>
                    </div>
                  </div>
                  <a
                    href={deal.marketplaceUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition"
                  >
                    View on {deal.marketplace}
                    <ExternalLink size={16} />
                  </a>
                </div>
              </div>
            </Card>

            {/* Price History Chart */}
            <Card className="p-6">
              <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center gap-2">
                <TrendingUp size={20} className="text-blue-600" />
                Price History (30 Days)
              </h3>
              {deal.priceHistory && deal.priceHistory.length > 0 ? (
                <ResponsiveContainer width="100%" height={300}>
                  <LineChart data={deal.priceHistory}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
                    <XAxis dataKey="date" stroke="#64748b" />
                    <YAxis stroke="#64748b" />
                    <Tooltip
                      contentStyle={{
                        backgroundColor: '#ffffff',
                        border: '1px solid #e2e8f0',
                        borderRadius: '8px',
                      }}
                      formatter={(value) => `$${value.toFixed(2)}`}
                    />
                    <Line
                      type="monotone"
                      dataKey="price"
                      stroke="#2563eb"
                      strokeWidth={2}
                      dot={{ fill: '#2563eb', r: 4 }}
                      activeDot={{ r: 6 }}
                    />
                  </LineChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-64 flex items-center justify-center text-slate-400">
                  No price history available
                </div>
              )}
            </Card>
          </div>

          {/* Sidebar - Pricing & Calculator */}
          <div className="space-y-6">
            {/* Pricing Card */}
            <Card className="p-6 bg-gradient-to-br from-blue-50 to-blue-100 border-blue-200">
              <h3 className="text-lg font-semibold text-slate-900 mb-4">Pricing</h3>
              <div className="space-y-3">
                <div className="flex justify-between">
                  <span className="text-slate-600">You Pay</span>
                  <span className="font-semibold text-slate-900">${deal.buyPrice.toFixed(2)}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-600">You Get</span>
                  <span className="font-semibold text-slate-900">${deal.sellPrice.toFixed(2)}</span>
                </div>
                <div className="h-px bg-blue-200"></div>
                <div className="flex justify-between">
                  <span className="text-slate-600">Profit</span>
                  <span className="font-semibold text-green-600">
                    ${(deal.sellPrice - deal.buyPrice).toFixed(2)}
                  </span>
                </div>
              </div>
            </Card>

            {/* Flip Score Card */}
            <Card className="p-6 bg-gradient-to-br from-purple-50 to-purple-100 border-purple-200">
              <h3 className="text-lg font-semibold text-slate-900 mb-4">Flip Score</h3>
              <div className="text-center">
                <div className="text-5xl font-bold text-purple-600 mb-2">{deal.flipScore}</div>
                <p className="text-slate-600 text-sm">Out of 100</p>
                <div className="mt-4 w-full bg-purple-200 rounded-full h-2">
                  <div
                    className="bg-purple-600 h-2 rounded-full"
                    style={{ width: `${(deal.flipScore / 100) * 100}%` }}
                  ></div>
                </div>
                <p className="text-slate-600 text-sm mt-3">
                  {deal.flipScore >= 80
                    ? 'Excellent opportunity'
                    : deal.flipScore >= 60
                      ? 'Good opportunity'
                      : 'Fair opportunity'}
                </p>
              </div>
            </Card>

            {/* Quality Score Card */}
            <Card className="p-6 bg-gradient-to-br from-green-50 to-green-100 border-green-200">
              <h3 className="text-lg font-semibold text-slate-900 mb-4">Quality Score</h3>
              <div className="text-center">
                <div className="text-5xl font-bold text-green-600 mb-2">{deal.qualityScore}</div>
                <p className="text-slate-600 text-sm">Out of 100</p>
                <div className="mt-4 w-full bg-green-200 rounded-full h-2">
                  <div
                    className="bg-green-600 h-2 rounded-full"
                    style={{ width: `${(deal.qualityScore / 100) * 100}%` }}
                  ></div>
                </div>
              </div>
            </Card>

            {/* Profit Calculator */}
            <Card className="p-6">
              <h3 className="text-lg font-semibold text-slate-900 mb-4">Profit Calculator</h3>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">
                    Marketplace Fees (%)
                  </label>
                  <input
                    type="number"
                    value={fees}
                    onChange={(e) => setFees(parseFloat(e.target.value) || 0)}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                    min="0"
                    max="100"
                    step="0.5"
                  />
                  <p className="text-xs text-slate-500 mt-1">Typical: eBay 12.9%, Amazon 15%, Etsy 6.5%</p>
                </div>

                <div className="p-4 bg-slate-50 rounded-lg space-y-3">
                  <div className="flex justify-between">
                    <span className="text-slate-600">Buy Price</span>
                    <span className="font-medium">${deal.buyPrice.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-slate-600">Sell Price</span>
                    <span className="font-medium">${deal.sellPrice.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-slate-600">Fees ({fees}%)</span>
                    <span className="font-medium">-${((deal.sellPrice * fees) / 100).toFixed(2)}</span>
                  </div>
                  <div className="h-px bg-slate-200"></div>
                  <div className="flex justify-between">
                    <span className="text-lg font-semibold text-slate-900">Net Profit</span>
                    <span className={`text-lg font-bold ${netProfit > 0 ? 'text-green-600' : 'text-red-600'}`}>
                      ${netProfit.toFixed(2)}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-slate-600">Profit Margin</span>
                    <span className={`font-medium ${parseFloat(netMargin) > 0 ? 'text-green-600' : 'text-red-600'}`}>
                      {netMargin}%
                    </span>
                  </div>
                </div>

                <Button
                  onClick={handleSaveDeal}
                  disabled={saveDealMutation.isPending}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-lg font-medium transition disabled:opacity-50"
                >
                  {saveDealMutation.isPending ? 'Saving...' : isSaved ? 'Deal Saved ✓' : 'Save This Deal'}
                </Button>
              </div>
            </Card>
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
}
