import { useState } from 'react';
import { Plus, Pause, Play, Trash2, TrendingUp, Clock } from 'lucide-react';
import DashboardLayout from '@/components/dashboard/DashboardLayout';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';

interface Monitor {
  id: number;
  name: string;
  keyword: string;
  marketplaces: string[];
  status: 'active' | 'paused';
  dealsFound: number;
  lastRun: string;
  nextRun: string;
}

export default function Monitors() {
  const [monitors, setMonitors] = useState<Monitor[]>([
    {
      id: 1,
      name: 'Gaming Laptops',
      keyword: 'gaming laptop',
      marketplaces: ['Amazon', 'eBay'],
      status: 'active',
      dealsFound: 12,
      lastRun: '2 hours ago',
      nextRun: 'In 4 hours',
    },
    {
      id: 2,
      name: 'iPhone Deals',
      keyword: 'iPhone 13',
      marketplaces: ['Facebook', 'Vinted', 'OfferUp'],
      status: 'active',
      dealsFound: 8,
      lastRun: '30 minutes ago',
      nextRun: 'In 5 hours 30 minutes',
    },
    {
      id: 3,
      name: 'Vintage Cameras',
      keyword: 'vintage camera',
      marketplaces: ['eBay', 'Etsy'],
      status: 'paused',
      dealsFound: 3,
      lastRun: '1 day ago',
      nextRun: 'Paused',
    },
  ]);

  const [showCreateModal, setShowCreateModal] = useState(false);
  const [newMonitor, setNewMonitor] = useState({
    name: '',
    keyword: '',
    marketplaces: [] as string[],
  });

  const handleLogout = () => {
    console.log('Logout clicked');
  };

  const toggleMonitorStatus = (id: number) => {
    setMonitors((prev) =>
      prev.map((m) =>
        m.id === id ? { ...m, status: m.status === 'active' ? 'paused' : 'active' } : m
      )
    );
  };

  const deleteMonitor = (id: number) => {
    setMonitors((prev) => prev.filter((m) => m.id !== id));
  };

  const createMonitor = () => {
    if (!newMonitor.name || !newMonitor.keyword) {
      alert('Please fill in all fields');
      return;
    }

    const monitor: Monitor = {
      id: Math.max(...monitors.map((m) => m.id), 0) + 1,
      name: newMonitor.name,
      keyword: newMonitor.keyword,
      marketplaces: newMonitor.marketplaces.length > 0 ? newMonitor.marketplaces : ['All'],
      status: 'active',
      dealsFound: 0,
      lastRun: 'Just now',
      nextRun: 'In 24 hours',
    };

    setMonitors((prev) => [monitor, ...prev]);
    setNewMonitor({ name: '', keyword: '', marketplaces: [] });
    setShowCreateModal(false);
  };

  return (
    <DashboardLayout currentPage="monitors" onLogout={handleLogout} userTier="free">
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Saved Searches</h2>
            <p className="text-slate-600 mt-1">Get alerts when new deals match your searches</p>
          </div>
          <Button
            onClick={() => setShowCreateModal(true)}
            className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg flex items-center gap-2"
          >
            <Plus size={20} />
            New Search
          </Button>
        </div>

        {/* Create Monitor Modal */}
        {showCreateModal && (
          <Card className="p-6 bg-blue-50 border-blue-200">
            <h3 className="text-lg font-semibold text-slate-900 mb-4">Create New Saved Search</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Search Name</label>
                <input
                  type="text"
                  placeholder="e.g., Gaming Laptops"
                  value={newMonitor.name}
                  onChange={(e) => setNewMonitor((prev) => ({ ...prev, name: e.target.value }))}
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">What to search for</label>
                <input
                  type="text"
                  placeholder="e.g., gaming laptop"
                  value={newMonitor.keyword}
                  onChange={(e) => setNewMonitor((prev) => ({ ...prev, keyword: e.target.value }))}
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Marketplaces</label>
                <div className="grid grid-cols-3 gap-2">
                  {['Amazon', 'eBay', 'Vinted', 'Facebook', 'Craigslist', 'Gumtree'].map((mp) => (
                    <button
                      key={mp}
                      onClick={() =>
                        setNewMonitor((prev) => ({
                          ...prev,
                          marketplaces: prev.marketplaces.includes(mp)
                            ? prev.marketplaces.filter((m) => m !== mp)
                            : [...prev.marketplaces, mp],
                        }))
                      }
                      className={`px-3 py-2 rounded-lg text-sm font-medium transition ${
                        newMonitor.marketplaces.includes(mp)
                          ? 'bg-blue-600 text-white'
                          : 'bg-white border border-slate-300 text-slate-700 hover:border-blue-500'
                      }`}
                    >
                      {mp}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex gap-3">
                <Button
                  onClick={createMonitor}
                  className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg"
                >
                  Create Monitor
                </Button>
                <Button
                  onClick={() => setShowCreateModal(false)}
                  className="bg-slate-200 hover:bg-slate-300 text-slate-900 px-6 py-2 rounded-lg"
                >
                  Cancel
                </Button>
              </div>
            </div>
          </Card>
        )}

        {/* Monitors List */}
        <div className="space-y-4">
          {monitors.length === 0 ? (
            <Card className="p-12 text-center">
              <TrendingUp size={48} className="mx-auto text-slate-300 mb-4" />
              <h3 className="text-xl font-semibold text-slate-900 mb-2">No Monitors Yet</h3>
              <p className="text-slate-600 mb-6">Create your first monitor to start tracking deals automatically.</p>
              <Button
                onClick={() => setShowCreateModal(true)}
                className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg"
              >
                Create Monitor
              </Button>
            </Card>
          ) : (
            monitors.map((monitor) => (
              <Card key={monitor.id} className="p-6 hover:shadow-lg transition">
                <div className="flex items-start justify-between mb-4">
                  <div>
                    <h3 className="text-lg font-semibold text-slate-900">{monitor.name}</h3>
                    <p className="text-slate-600 text-sm">Keyword: {monitor.keyword}</p>
                  </div>
                  <div
                    className={`px-3 py-1 rounded-full text-xs font-semibold ${
                      monitor.status === 'active'
                        ? 'bg-green-100 text-green-800'
                        : 'bg-slate-100 text-slate-800'
                    }`}
                  >
                    {monitor.status === 'active' ? '● Active' : '● Paused'}
                  </div>
                </div>

                <div className="grid grid-cols-4 gap-4 mb-4 p-4 bg-slate-50 rounded-lg">
                  <div>
                    <p className="text-xs text-slate-600">Deals Found</p>
                    <p className="font-semibold text-slate-900">{monitor.dealsFound}</p>
                  </div>
                  <div>
                    <p className="text-xs text-slate-600">Last Run</p>
                    <p className="font-semibold text-slate-900 text-sm">{monitor.lastRun}</p>
                  </div>
                  <div>
                    <p className="text-xs text-slate-600">Next Run</p>
                    <p className="font-semibold text-slate-900 text-sm">{monitor.nextRun}</p>
                  </div>
                  <div>
                    <p className="text-xs text-slate-600">Marketplaces</p>
                    <p className="font-semibold text-slate-900 text-sm">{monitor.marketplaces.join(', ')}</p>
                  </div>
                </div>

                <div className="flex gap-3">
                  <button
                    onClick={() => toggleMonitorStatus(monitor.id)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg transition ${
                      monitor.status === 'active'
                        ? 'bg-yellow-100 text-yellow-800 hover:bg-yellow-200'
                        : 'bg-green-100 text-green-800 hover:bg-green-200'
                    }`}
                  >
                    {monitor.status === 'active' ? (
                      <>
                        <Pause size={16} />
                        Pause
                      </>
                    ) : (
                      <>
                        <Play size={16} />
                        Resume
                      </>
                    )}
                  </button>
                  <button className="flex items-center gap-2 px-4 py-2 bg-blue-100 text-blue-800 rounded-lg hover:bg-blue-200 transition">
                    <Clock size={16} />
                    View Deals
                  </button>
                  <button
                    onClick={() => deleteMonitor(monitor.id)}
                    className="flex items-center gap-2 px-4 py-2 bg-red-100 text-red-800 rounded-lg hover:bg-red-200 transition"
                  >
                    <Trash2 size={16} />
                    Delete
                  </button>
                </div>
              </Card>
            ))
          )}
        </div>

        {/* Info Box */}
        <Card className="p-6 bg-blue-50 border-blue-200">
          <h3 className="font-semibold text-slate-900 mb-2">📊 How Monitors Work</h3>
          <ul className="space-y-2 text-sm text-slate-700">
            <li>✓ Monitors run automatically every 24 hours (Free tier)</li>
            <li>✓ Pro tier: Every 6 hours | Enterprise: Every 1 hour</li>
            <li>✓ You'll get alerts when new deals matching your criteria are found</li>
            <li>✓ Free tier: Up to 5 monitors | Pro: Up to 15 | Enterprise: Unlimited</li>
          </ul>
        </Card>
      </div>
    </DashboardLayout>
  );
}
