import { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Search as SearchIcon, Filter, TrendingUp, AlertCircle, Loader } from 'lucide-react';
import DashboardLayout from '@/components/dashboard/DashboardLayout';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { trpc } from '@/lib/trpc';
import { useAuth } from '@/contexts/AuthContext';

const MARKETPLACE_MAP: Record<string, string> = {
  'Amazon': 'amazon',
  'eBay': 'ebay',
  'Vinted': 'vinted',
  'Facebook': 'facebook',
  'Craigslist': 'craigslist',
  'Gumtree': 'gumtree',
  'Poshmark': 'poshmark',
  'Depop': 'depop',
  'Mercari': 'mercari',
  'Etsy': 'etsy',
  'OfferUp': 'offerup',
  'Shpock': 'shpock',
};

const MARKETPLACES = Object.keys(MARKETPLACE_MAP);

interface SearchResult {
  dealId: string;
  title: string;
  marketplace: string;
  buyPrice: number;
  sellPrice: number;
  estimatedProfit: number;
  profitMargin: number;
  flipScore: number;
  qualityScore: number;
  condition: string;
  imageUrl?: string;
  flagged: boolean;
  flagReason?: string;
}

export default function FastLaneSearch() {
  const navigate = useNavigate();
  const { user } = useAuth();
  
  const [keyword, setKeyword] = useState('');
  const [selectedMarketplaces, setSelectedMarketplaces] = useState<string[]>([]);
  const [minPrice, setMinPrice] = useState('');
  const [maxPrice, setMaxPrice] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState('flipScore');
  const [error, setError] = useState<string | null>(null);

  // tRPC hooks
  const searchMutation = trpc.deals.search.useMutation();
  const quotaQuery = trpc.quotas.getCurrent.useQuery();

  const handleSearch = useCallback(async () => {
    if (!keyword.trim()) {
      setError('Please enter a search keyword');
      return;
    }

    if (selectedMarketplaces.length === 0) {
      setError('Please select at least one marketplace');
      return;
    }

    setError(null);

    try {
      const response = await searchMutation.mutateAsync({
        keyword: keyword.trim(),
        category: undefined,
        condition: 'any',
        minPrice: minPrice ? parseFloat(minPrice) : undefined,
        maxPrice: maxPrice ? parseFloat(maxPrice) : undefined,
        marketplaces: selectedMarketplaces.map(m => MARKETPLACE_MAP[m]),
      });

      if (response.success) {
        // Transform response deals to SearchResult format
        const transformedResults: SearchResult[] = response.deals.map(deal => ({
          dealId: deal.dealId,
          title: deal.title,
          marketplace: deal.marketplace,
          buyPrice: deal.buyPrice,
          sellPrice: deal.sellPrice,
          estimatedProfit: deal.estimatedProfit,
          profitMargin: deal.profitMargin,
          flipScore: deal.flipScore,
          qualityScore: deal.qualityScore,
          condition: deal.condition,
          imageUrl: deal.imageUrl,
          flagged: deal.flagged,
          flagReason: deal.flagReason,
        }));

        // Sort results
        const sorted = [...transformedResults].sort((a, b) => {
          switch (sortBy) {
            case 'flipScore':
              return b.flipScore - a.flipScore;
            case 'profitMargin':
              return b.profitMargin - a.profitMargin;
            case 'buyPrice':
              return a.buyPrice - b.buyPrice;
            default:
              return 0;
          }
        });

        setResults(sorted);
      } else {
        setError('Search failed. Please try again.');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Search failed');
    }
  }, [keyword, selectedMarketplaces, minPrice, maxPrice, searchMutation]);

  const toggleMarketplace = (marketplace: string) => {
    setSelectedMarketplaces((prev) =>
      prev.includes(marketplace) ? prev.filter((m) => m !== marketplace) : [...prev, marketplace]
    );
  };

  const handleViewDetails = (deal: SearchResult) => {
    navigate(`/deals/${deal.dealId}?marketplace=${deal.marketplace}`);
  };

  const handleSaveDeal = async (deal: SearchResult) => {
    try {
      // TODO: Implement save deal mutation
      alert('Deal saved! (Feature coming soon)');
    } catch (err) {
      setError('Failed to save deal');
    }
  };

  const userTier = user?.tier || 'free';
  const quotaRemaining = quotaQuery.data?.dailySearchLimit ? 
    (quotaQuery.data.dailySearchLimit - (quotaQuery.data.dailySearchesUsed || 0)) : 
    0;

  return (
    <DashboardLayout currentPage="search" userTier={userTier}>
      <div className="space-y-6">
        {/* Search Form */}
        <Card className="p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-2xl font-bold text-white">Find Your Next Deal</h2>
            {quotaRemaining !== null && (
              <div className="text-sm text-[#9CA3AF]">
                <span className="font-medium text-[#10B981]">{quotaRemaining}</span> searches left today
              </div>
            )}
          </div>

          {/* Main Search Input */}
          <div className="flex gap-3 mb-6">
            <div className="flex-1 relative">
              <SearchIcon className="absolute left-3 top-3 text-[#6B7280]" size={20} />
              <input
                type="text"
                placeholder="Nike shoes, gaming laptops, vintage watches..."
                value={keyword}
                onChange={(e) => setKeyword(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
                className="w-full pl-10 pr-4 py-3 bg-[#1A1F3A] border border-[#374151] text-white rounded-xl focus:outline-none focus:border-[#7C3AED] focus:ring-2 focus:ring-purple-500/30 placeholder-[#6B7280]"
              />
            </div>
            <Button
              onClick={handleSearch}
              disabled={searchMutation.isPending}
              variant="primary"
              className="flex items-center gap-2"
            >
              {searchMutation.isPending ? (
                <>
                  <Loader size={18} className="animate-spin" />
                  Searching...
                </>
              ) : (
                'Search'
              )}
            </Button>
            <button
              onClick={() => setShowFilters(!showFilters)}
              className="p-3 border border-[#374151] rounded-xl hover:bg-[#252D48] transition bg-[#1A1F3A] text-[#9CA3AF]"
            >
              <Filter size={20} />
            </button>
          </div>

          {/* Error Message */}
          {error && (
            <div className="mb-6 p-4 bg-red-500/10 border border-red-500/30 rounded-lg flex items-start gap-3">
              <AlertCircle size={20} className="text-red-400 flex-shrink-0 mt-0.5" />
              <div>
                <p className="font-medium text-red-900">{error}</p>
              </div>
            </div>
          )}

          {/* Filters */}
          {showFilters && (
            <div className="space-y-4 p-4 bg-slate-50 rounded-lg border border-slate-200">
              {/* Price Range */}
              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Min Price</label>
                  <input
                    type="number"
                    placeholder="$0"
                    value={minPrice}
                    onChange={(e) => setMinPrice(e.target.value)}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Max Price</label>
                  <input
                    type="number"
                    placeholder="$10000"
                    value={maxPrice}
                    onChange={(e) => setMaxPrice(e.target.value)}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              </div>

              {/* Marketplace Selection */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-3">Marketplaces</label>
                <div className="grid grid-cols-3 md:grid-cols-4 gap-2">
                  {MARKETPLACES.map((marketplace) => (
                    <button
                      key={marketplace}
                      onClick={() => toggleMarketplace(marketplace)}
                      className={`px-3 py-2 rounded-lg text-sm font-medium transition ${
                        selectedMarketplaces.includes(marketplace)
                          ? 'bg-blue-600 text-white'
                          : 'bg-white border border-slate-300 text-slate-700 hover:border-blue-500'
                      }`}
                    >
                      {marketplace}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}
        </Card>

        {/* Results */}
        {results.length > 0 && (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-900">
                {results.length} {results.length === 1 ? 'Deal' : 'Deals'} Found
              </h3>
              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="flipScore">Sort by Flip Score (High to Low)</option>
                <option value="profitMargin">Sort by Profit Margin (High to Low)</option>
                <option value="buyPrice">Sort by Price (Low to High)</option>
              </select>
            </div>

            {results.map((deal) => (
              <Card key={`${deal.marketplace}-${deal.dealId}`} className="p-6 hover:shadow-lg transition">
                <div className="flex gap-6">
                  {/* Image Placeholder */}
                  <div className="w-24 h-24 bg-slate-200 rounded-lg flex-shrink-0 flex items-center justify-center overflow-hidden">
                    {deal.imageUrl ? (
                      <img src={deal.imageUrl} alt={deal.title} className="w-full h-full object-cover" />
                    ) : (
                      <span className="text-slate-400 text-sm">No Image</span>
                    )}
                  </div>

                  {/* Deal Info */}
                  <div className="flex-1">
                    <div className="flex items-start justify-between mb-3">
                      <div>
                        <div className="flex items-center gap-2 mb-1">
                          <span className="px-2 py-1 bg-blue-100 text-blue-800 rounded text-xs font-medium">
                            {deal.marketplace}
                          </span>
                          {deal.flagged && (
                            <span className="px-2 py-1 bg-red-100 text-red-800 rounded text-xs font-medium">
                              Flagged
                            </span>
                          )}
                        </div>
                        <h4 className="text-lg font-semibold text-slate-900">{deal.title}</h4>
                        <p className="text-sm text-slate-600">{deal.condition}</p>
                      </div>
                      <div className="text-right">
                        <div className="flex items-center gap-2 mb-1">
                          <TrendingUp size={18} className="text-green-600" />
                          <span className="text-2xl font-bold text-green-600">
                            +${deal.estimatedProfit.toFixed(2)}
                          </span>
                        </div>
                        <p className="text-sm text-slate-600">Potential Profit</p>
                      </div>
                    </div>

                    {/* Stats */}
                    <div className="grid grid-cols-5 gap-4 mb-4">
                      <div>
                        <p className="text-xs text-slate-600">Buy Price</p>
                        <p className="font-semibold text-slate-900">${deal.buyPrice.toFixed(2)}</p>
                      </div>
                      <div>
                        <p className="text-xs text-slate-600">Est. Sell</p>
                        <p className="font-semibold text-slate-900">${deal.sellPrice.toFixed(2)}</p>
                      </div>
                      <div>
                        <p className="text-xs text-slate-600">Profit Margin</p>
                        <p className="font-semibold text-green-600">{deal.profitMargin.toFixed(1)}%</p>
                      </div>
                      <div>
                        <p className="text-xs text-slate-600">Flip Score</p>
                        <p className="font-semibold text-blue-600">{deal.flipScore}/100</p>
                      </div>
                      <div>
                        <p className="text-xs text-slate-600">Quality</p>
                        <p className="font-semibold text-purple-600">{deal.qualityScore}/100</p>
                      </div>
                    </div>

                    {/* Actions */}
                    <div className="flex gap-3">
              <Button
                onClick={() => handleViewDetails(deal)}
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg"
              >
                View
              </Button>
              <Button
                onClick={() => handleSaveDeal(deal)}
                className="bg-slate-200 hover:bg-slate-300 text-slate-900 px-4 py-2 rounded-lg"
              >
                Save
              </Button>
                    </div>
                  </div>
                </div>
              </Card>
            ))}
          </div>
        )}

        {/* Empty State */}
        {!searchMutation.isPending && results.length === 0 && !error && (
          <Card className="p-12 text-center">
            <SearchIcon size={48} className="mx-auto text-slate-300 mb-4" />
            <h3 className="text-xl font-semibold text-slate-900 mb-2">Start Searching</h3>
            <p className="text-slate-600">Search for products across 12 marketplaces to find the best prices or flip opportunities.</p>
          </Card>
        )}

        {/* Loading State */}
        {searchMutation.isPending && (
          <Card className="p-12 text-center">
            <Loader size={48} className="mx-auto text-blue-400 mb-4 animate-spin" />
            <h3 className="text-xl font-semibold text-slate-900 mb-2">Searching Marketplaces</h3>
            <p className="text-slate-600">Searching across {selectedMarketplaces.length} marketplaces...</p>
          </Card>
        )}
      </div>
    </DashboardLayout>
  );
}
