import { useState } from 'react';
import { ChevronRight, ChevronLeft, Zap, Search, Check, AlertCircle } from 'lucide-react';
import DashboardLayout from '@/components/dashboard/DashboardLayout';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';

type Step = 'search' | 'filters' | 'marketplaces' | 'review' | 'generating' | 'results';

interface SearchCriteria {
  keyword: string;
  category: string;
  condition: string;
  minPrice: string;
  maxPrice: string;
  selectedMarketplaces: string[];
  sortBy: 'flipScore' | 'price' | 'freshness';
}

const CATEGORIES = [
  'Electronics',
  'Fashion',
  'Home & Garden',
  'Sports & Outdoors',
  'Toys & Games',
  'Books & Media',
  'Collectibles',
  'Jewelry & Watches',
  'Automotive',
  'All Categories',
];

const CONDITIONS = ['Any', 'New', 'Like New', 'Good', 'Fair', 'Poor'];

const MARKETPLACES = [
  'Amazon',
  'eBay',
  'Vinted',
  'Facebook',
  'Craigslist',
  'Gumtree',
  'Poshmark',
  'Depop',
  'Mercari',
  'Etsy',
  'OfferUp',
  'Shpock',
];

const SORT_OPTIONS = [
  { value: 'flipScore', label: 'Flip Score (Best)' },
  { value: 'price', label: 'Price (Low to High)' },
  { value: 'freshness', label: 'Newest First' },
];

export default function DealGenerator() {
  const [currentStep, setCurrentStep] = useState<Step>('search');
  const [criteria, setCriteria] = useState<SearchCriteria>({
    keyword: '',
    category: 'All Categories',
    condition: 'Any',
    minPrice: '',
    maxPrice: '',
    selectedMarketplaces: [],
    sortBy: 'flipScore',
  });
  const [generatingProgress, setGeneratingProgress] = useState(0);

  const handleLogout = () => {
    console.log('Logout clicked');
  };

  const steps: Step[] = ['search', 'filters', 'marketplaces', 'review', 'generating', 'results'];
  const currentStepIndex = steps.indexOf(currentStep);

  const nextStep = () => {
    if (currentStepIndex < steps.length - 1) {
      const nextStepValue = steps[currentStepIndex + 1];
      if (nextStepValue === 'generating') {
        // Simulate search generation
        setCurrentStep('generating');
        simulateGeneration();
      } else {
        setCurrentStep(nextStepValue);
      }
    }
  };

  const prevStep = () => {
    if (currentStepIndex > 0) {
      setCurrentStep(steps[currentStepIndex - 1]);
    }
  };

  const simulateGeneration = () => {
    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 30;
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);
        setTimeout(() => {
          setCurrentStep('results');
        }, 500);
      }
      setGeneratingProgress(Math.min(progress, 100));
    }, 300);
  };

  const toggleMarketplace = (marketplace: string) => {
    setCriteria((prev) => ({
      ...prev,
      selectedMarketplaces: prev.selectedMarketplaces.includes(marketplace)
        ? prev.selectedMarketplaces.filter((m) => m !== marketplace)
        : [...prev.selectedMarketplaces, marketplace],
    }));
  };

  const handleSearch = () => {
    console.log('Starting search with criteria:', criteria);
    nextStep();
  };

  const getStepTitle = () => {
    switch (currentStep) {
      case 'search':
        return 'What are you looking for?';
      case 'filters':
        return 'Refine your search';
      case 'marketplaces':
        return 'Select marketplaces';
      case 'review':
        return 'Review your search';
      case 'generating':
        return 'Generating deals...';
      case 'results':
        return 'Your deals are ready!';
      default:
        return '';
    }
  };

  const getStepDescription = () => {
    switch (currentStep) {
      case 'search':
        return 'Enter keywords to find deals across all marketplaces';
      case 'filters':
        return 'Narrow down results by category, condition, and price';
      case 'marketplaces':
        return 'Choose which marketplaces to search';
      case 'review':
        return 'Review your search parameters before generating';
      case 'generating':
        return 'Searching across marketplaces and scoring deals...';
      case 'results':
        return 'Found amazing deals matching your criteria';
      default:
        return '';
    }
  };

  const canProceed = () => {
    switch (currentStep) {
      case 'search':
        return criteria.keyword.trim().length > 0;
      case 'filters':
        return true;
      case 'marketplaces':
        return criteria.selectedMarketplaces.length > 0;
      case 'review':
        return true;
      default:
        return false;
    }
  };

  return (
    <DashboardLayout currentPage="generator" onLogout={handleLogout} userTier="free">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="mb-12">
          <h1 className="text-4xl font-bold text-white mb-2">Deal Generator</h1>
          <p className="text-gray-400">Find profitable deals across 12 marketplaces</p>
        </div>

        {/* Progress Indicator */}
        <div className="mb-12">
          <div className="flex items-center justify-between mb-8">
            {steps.map((step, idx) => (
              <div key={step} className="flex items-center flex-1">
                <div
                  className={`w-12 h-12 rounded-full flex items-center justify-center font-semibold transition-all ${
                    idx < currentStepIndex
                      ? 'bg-green-500 text-white'
                      : idx === currentStepIndex
                      ? 'bg-purple-600 text-white ring-4 ring-purple-400 ring-opacity-30'
                      : 'bg-gray-700 text-gray-400'
                  }`}
                >
                  {idx < currentStepIndex ? <Check size={20} /> : idx + 1}
                </div>
                {idx < steps.length - 1 && (
                  <div
                    className={`h-1 flex-1 mx-3 transition-all ${
                      idx < currentStepIndex ? 'bg-green-500' : 'bg-gray-700'
                    }`}
                  />
                )}
              </div>
            ))}
          </div>

          {/* Step Title & Description */}
          <div className="text-center">
            <h2 className="text-3xl font-bold text-white mb-2">{getStepTitle()}</h2>
            <p className="text-gray-400">{getStepDescription()}</p>
          </div>
        </div>

        {/* Step Content */}
        <Card className="p-10 mb-8 bg-gray-900 border-gray-800">
          {/* Step 1: Search */}
          {currentStep === 'search' && (
            <div className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-3">Search Keywords</label>
                <div className="relative">
                  <Search className="absolute left-4 top-4 text-gray-500" size={20} />
                  <input
                    type="text"
                    placeholder="e.g., Nike shoes, gaming laptop, vintage watch..."
                    value={criteria.keyword}
                    onChange={(e) => setCriteria((prev) => ({ ...prev, keyword: e.target.value }))}
                    className="w-full pl-12 pr-4 py-4 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent transition"
                  />
                </div>
                <p className="text-xs text-gray-500 mt-2">Be specific for better results</p>
              </div>

              {/* Quick Suggestions */}
              <div>
                <p className="text-xs font-semibold text-gray-400 mb-3 uppercase">Popular searches</p>
                <div className="flex flex-wrap gap-2">
                  {['Nike shoes', 'Gaming laptop', 'Vintage watch', 'Designer handbag', 'Collectible figure'].map((suggestion) => (
                    <button
                      key={suggestion}
                      onClick={() => setCriteria((prev) => ({ ...prev, keyword: suggestion }))}
                      className="px-3 py-2 bg-gray-800 hover:bg-gray-700 border border-gray-700 rounded-lg text-sm text-gray-300 transition"
                    >
                      {suggestion}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}

          {/* Step 2: Filters */}
          {currentStep === 'filters' && (
            <div className="space-y-8">
              {/* Category */}
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-4">Category</label>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  {CATEGORIES.map((cat) => (
                    <button
                      key={cat}
                      onClick={() => setCriteria((prev) => ({ ...prev, category: cat }))}
                      className={`p-4 rounded-lg border-2 transition font-medium ${
                        criteria.category === cat
                          ? 'border-purple-500 bg-purple-500 bg-opacity-20 text-purple-300'
                          : 'border-gray-700 bg-gray-800 text-gray-300 hover:border-purple-500 hover:border-opacity-50'
                      }`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>

              {/* Condition */}
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-4">Condition</label>
                <div className="grid grid-cols-3 md:grid-cols-6 gap-3">
                  {CONDITIONS.map((cond) => (
                    <button
                      key={cond}
                      onClick={() => setCriteria((prev) => ({ ...prev, condition: cond }))}
                      className={`p-3 rounded-lg border-2 transition font-medium text-sm ${
                        criteria.condition === cond
                          ? 'border-green-500 bg-green-500 bg-opacity-20 text-green-300'
                          : 'border-gray-700 bg-gray-800 text-gray-300 hover:border-green-500 hover:border-opacity-50'
                      }`}
                    >
                      {cond}
                    </button>
                  ))}
                </div>
              </div>

              {/* Price Range */}
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-4">Price Range</label>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs text-gray-400 mb-2 block">Minimum</label>
                    <div className="relative">
                      <span className="absolute left-3 top-3 text-gray-500">$</span>
                      <input
                        type="number"
                        placeholder="0"
                        value={criteria.minPrice}
                        onChange={(e) => setCriteria((prev) => ({ ...prev, minPrice: e.target.value }))}
                        className="w-full pl-8 pr-4 py-3 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="text-xs text-gray-400 mb-2 block">Maximum</label>
                    <div className="relative">
                      <span className="absolute left-3 top-3 text-gray-500">$</span>
                      <input
                        type="number"
                        placeholder="10000"
                        value={criteria.maxPrice}
                        onChange={(e) => setCriteria((prev) => ({ ...prev, maxPrice: e.target.value }))}
                        className="w-full pl-8 pr-4 py-3 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition"
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* Sort By */}
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-4">Sort By</label>
                <div className="grid grid-cols-3 gap-3">
                  {SORT_OPTIONS.map((option) => (
                    <button
                      key={option.value}
                      onClick={() => setCriteria((prev) => ({ ...prev, sortBy: option.value as any }))}
                      className={`p-3 rounded-lg border-2 transition font-medium text-sm ${
                        criteria.sortBy === option.value
                          ? 'border-cyan-500 bg-cyan-500 bg-opacity-20 text-cyan-300'
                          : 'border-gray-700 bg-gray-800 text-gray-300 hover:border-cyan-500 hover:border-opacity-50'
                      }`}
                    >
                      {option.label}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}

          {/* Step 3: Marketplaces */}
          {currentStep === 'marketplaces' && (
            <div className="space-y-6">
              <p className="text-gray-400">Select which marketplaces to search</p>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                {MARKETPLACES.map((mp) => (
                  <button
                    key={mp}
                    onClick={() => toggleMarketplace(mp)}
                    className={`px-4 py-4 rounded-lg border-2 transition font-medium text-sm ${
                      criteria.selectedMarketplaces.includes(mp)
                        ? 'border-green-500 bg-green-500 bg-opacity-20 text-green-300'
                        : 'border-gray-700 bg-gray-800 text-gray-300 hover:border-green-500 hover:border-opacity-50'
                    }`}
                  >
                    {mp}
                  </button>
                ))}
              </div>

              {criteria.selectedMarketplaces.length === 0 && (
                <div className="p-4 bg-red-500 bg-opacity-10 border border-red-500 border-opacity-30 rounded-lg flex items-start gap-3">
                  <AlertCircle size={18} className="text-red-400 flex-shrink-0 mt-0.5" />
                  <p className="text-sm text-red-300">Select at least one marketplace to proceed</p>
                </div>
              )}

              {criteria.selectedMarketplaces.length > 0 && (
                <div className="p-4 bg-green-500 bg-opacity-10 border border-green-500 border-opacity-30 rounded-lg">
                  <p className="text-sm text-green-300">
                    ✓ Searching <strong>{criteria.selectedMarketplaces.length}</strong> marketplace{criteria.selectedMarketplaces.length !== 1 ? 's' : ''}
                  </p>
                </div>
              )}
            </div>
          )}

          {/* Step 4: Review */}
          {currentStep === 'review' && (
            <div className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 bg-gray-800 rounded-lg border border-gray-700">
                  <p className="text-xs text-gray-400 mb-2">Search Query</p>
                  <p className="text-lg font-semibold text-white">{criteria.keyword}</p>
                </div>
                <div className="p-4 bg-gray-800 rounded-lg border border-gray-700">
                  <p className="text-xs text-gray-400 mb-2">Category</p>
                  <p className="text-lg font-semibold text-white">{criteria.category}</p>
                </div>
                <div className="p-4 bg-gray-800 rounded-lg border border-gray-700">
                  <p className="text-xs text-gray-400 mb-2">Condition</p>
                  <p className="text-lg font-semibold text-white">{criteria.condition}</p>
                </div>
                <div className="p-4 bg-gray-800 rounded-lg border border-gray-700">
                  <p className="text-xs text-gray-400 mb-2">Price Range</p>
                  <p className="text-lg font-semibold text-white">
                    ${criteria.minPrice || '0'} - ${criteria.maxPrice || '∞'}
                  </p>
                </div>
              </div>

              <div className="p-4 bg-purple-500 bg-opacity-10 border border-purple-500 border-opacity-30 rounded-lg">
                <p className="text-sm text-purple-300 mb-2">
                  <strong>Marketplaces:</strong> {criteria.selectedMarketplaces.join(', ')}
                </p>
                <p className="text-sm text-purple-300">
                  <strong>Sort by:</strong> {SORT_OPTIONS.find((o) => o.value === criteria.sortBy)?.label}
                </p>
              </div>

              <div className="p-4 bg-teal-500 bg-opacity-10 border border-teal-500 border-opacity-30 rounded-lg flex items-start gap-3">
                <Zap size={18} className="text-teal-400 flex-shrink-0 mt-0.5" />
                <p className="text-sm text-teal-300">
                  Ready to search across <strong>{criteria.selectedMarketplaces.length}</strong> marketplace{criteria.selectedMarketplaces.length !== 1 ? 's' : ''}!
                </p>
              </div>
            </div>
          )}

          {/* Step 5: Generating */}
          {currentStep === 'generating' && (
            <div className="space-y-8 text-center">
              <div className="py-12">
                <div className="mb-8">
                  <div className="w-24 h-24 mx-auto relative">
                    <div className="absolute inset-0 rounded-full border-4 border-gray-700" />
                    <div
                      className="absolute inset-0 rounded-full border-4 border-transparent border-t-purple-500 border-r-green-500"
                      style={{
                        animation: 'spin 2s linear infinite',
                      }}
                    />
                    <div className="absolute inset-0 flex items-center justify-center">
                      <span className="text-2xl font-bold text-purple-400">{Math.round(generatingProgress)}%</span>
                    </div>
                  </div>
                </div>
                <p className="text-gray-300 mb-2">Searching across marketplaces...</p>
                <p className="text-sm text-gray-500">This usually takes 30-60 seconds</p>
              </div>

              {/* Progress Bar */}
              <div className="w-full bg-gray-800 rounded-full h-2 overflow-hidden">
                <div
                  className="h-full bg-gradient-to-r from-purple-500 via-green-500 to-teal-500 transition-all duration-300"
                  style={{ width: `${generatingProgress}%` }}
                />
              </div>
            </div>
          )}

          {/* Step 6: Results */}
          {currentStep === 'results' && (
            <div className="space-y-6">
              <div className="text-center py-8">
                <div className="w-20 h-20 mx-auto mb-4 bg-green-500 bg-opacity-20 rounded-full flex items-center justify-center">
                  <Check size={40} className="text-green-400" />
                </div>
                <h3 className="text-2xl font-bold text-white mb-2">Search Complete!</h3>
                <p className="text-gray-400">Found 247 deals matching your criteria</p>
              </div>

              <div className="grid grid-cols-3 gap-4">
                <div className="p-4 bg-gray-800 rounded-lg border border-gray-700 text-center">
                  <p className="text-3xl font-bold text-purple-400">247</p>
                  <p className="text-sm text-gray-400 mt-2">Total Deals</p>
                </div>
                <div className="p-4 bg-gray-800 rounded-lg border border-gray-700 text-center">
                  <p className="text-3xl font-bold text-green-400">8.2</p>
                  <p className="text-sm text-gray-400 mt-2">Avg Flip Score</p>
                </div>
                <div className="p-4 bg-gray-800 rounded-lg border border-gray-700 text-center">
                  <p className="text-3xl font-bold text-teal-400">$1.2K</p>
                  <p className="text-sm text-gray-400 mt-2">Avg Profit</p>
                </div>
              </div>

              <button className="w-full px-6 py-4 bg-gradient-to-r from-purple-600 to-green-600 hover:from-purple-700 hover:to-green-700 text-white rounded-lg font-semibold transition">
                View All Deals
              </button>
            </div>
          )}
        </Card>

        {/* Navigation Buttons */}
        <div className="flex gap-4 justify-between">
          <Button
            onClick={prevStep}
            disabled={currentStepIndex === 0 || currentStep === 'generating'}
            className="flex items-center gap-2 px-6 py-3 border border-gray-700 bg-gray-800 hover:bg-gray-700 text-gray-300 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition"
          >
            <ChevronLeft size={18} />
            Back
          </Button>

          {currentStep === 'results' ? (
            <Button
              onClick={() => {
                setCurrentStep('search');
                setCriteria({
                  keyword: '',
                  category: 'All Categories',
                  condition: 'Any',
                  minPrice: '',
                  maxPrice: '',
                  selectedMarketplaces: [],
                  sortBy: 'flipScore',
                });
                setGeneratingProgress(0);
              }}
              className="flex items-center gap-2 px-8 py-3 bg-gradient-to-r from-purple-600 to-green-600 hover:from-purple-700 hover:to-green-700 text-white rounded-lg transition"
            >
              <Zap size={18} />
              New Search
            </Button>
          ) : (
            <Button
              onClick={handleSearch}
              disabled={!canProceed() || currentStep === 'generating'}
              className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-purple-600 to-green-600 hover:from-purple-700 hover:to-green-700 text-white rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition"
            >
              {currentStep === 'review' ? (
                <>
                  <Zap size={18} />
                  Generate Deals
                </>
              ) : (
                <>
                  Next
                  <ChevronRight size={18} />
                </>
              )}
            </Button>
          )}
        </div>
      </div>

      <style>{`
        @keyframes spin {
          to {
            transform: rotate(360deg);
          }
        }
      `}</style>
    </DashboardLayout>
  );
}
