import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import LandingPage from './pages/LandingPage';
import Dashboard from './pages/Dashboard';
import FastLaneSearch from './pages/FastLaneSearch';
import DealGenerator from './pages/DealGenerator';
import DealDetail from './pages/DealDetail';
import Monitors from './pages/Monitors';

function App() {
  return (
    <Router>
      <Routes>
        {/* Public Routes */}
        <Route path="/" element={<LandingPage />} />
        <Route path="/landing" element={<LandingPage />} />

        {/* Dashboard Routes */}
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/dashboard/search" element={<FastLaneSearch />} />
        <Route path="/dashboard/generator" element={<DealGenerator />} />
        <Route path="/dashboard/deal/:dealId" element={<DealDetail />} />
        <Route path="/dashboard/monitors" element={<Monitors />} />

        {/* Fallback */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </Router>
  );
}

export default App;
