import { useState } from 'react';
import { Menu, X, LogOut, Settings, Home, Search, BookmarkIcon, BarChart3 } from 'lucide-react';
import { Button } from '@/components/ui/button';

interface DashboardLayoutProps {
  children: React.ReactNode;
  currentPage: string;
  onLogout: () => void;
  userTier: 'free' | 'pro' | 'enterprise';
  userName?: string;
}

export default function DashboardLayout({
  children,
  currentPage,
  onLogout,
  userTier,
  userName = 'User',
}: DashboardLayoutProps) {
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const navItems = [
    { id: 'home', label: 'Dashboard', icon: Home, href: '/dashboard' },
    { id: 'search', label: 'Fast Lane Search', icon: Search, href: '/dashboard/search' },
    { id: 'generator', label: 'Deal Generator', icon: BarChart3, href: '/dashboard/generator' },
    { id: 'monitors', label: 'Monitors', icon: BookmarkIcon, href: '/dashboard/monitors' },
  ];

  const tierColors = {
    free: 'bg-slate-100 text-slate-800',
    pro: 'bg-blue-100 text-blue-800',
    enterprise: 'bg-purple-100 text-purple-800',
  };

  return (
    <div className="flex h-screen bg-slate-50">
      {/* Sidebar */}
      <aside
        className={`${
          sidebarOpen ? 'w-64' : 'w-20'
        } bg-slate-900 text-white transition-all duration-300 flex flex-col border-r border-slate-800`}
      >
        {/* Logo */}
        <div className="p-4 border-b border-slate-800 flex items-center justify-between">
          {sidebarOpen && <h1 className="text-xl font-bold">resellerfinder</h1>}
          <button
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="p-1 hover:bg-slate-800 rounded transition"
          >
            {sidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 p-4 space-y-2">
          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = currentPage === item.id;
            return (
              <a
                key={item.id}
                href={item.href}
                className={`flex items-center gap-3 px-4 py-3 rounded-lg transition ${
                  isActive
                    ? 'bg-blue-600 text-white'
                    : 'text-slate-300 hover:bg-slate-800'
                }`}
              >
                <Icon size={20} />
                {sidebarOpen && <span>{item.label}</span>}
              </a>
            );
          })}
        </nav>

        {/* User Section */}
        <div className="p-4 border-t border-slate-800 space-y-3">
          {sidebarOpen && (
            <div className="space-y-2">
              <p className="text-sm text-slate-400">Logged in as</p>
              <p className="font-semibold truncate">{userName}</p>
              <div className={`inline-block px-3 py-1 rounded-full text-xs font-semibold ${tierColors[userTier]}`}>
                {userTier.charAt(0).toUpperCase() + userTier.slice(1)} Tier
              </div>
            </div>
          )}

          <div className="space-y-2">
            <button className="w-full flex items-center gap-2 px-4 py-2 rounded-lg text-slate-300 hover:bg-slate-800 transition">
              <Settings size={18} />
              {sidebarOpen && <span>Settings</span>}
            </button>
            <button
              onClick={onLogout}
              className="w-full flex items-center gap-2 px-4 py-2 rounded-lg text-slate-300 hover:bg-slate-800 transition"
            >
              <LogOut size={18} />
              {sidebarOpen && <span>Logout</span>}
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-auto">
        {/* Top Bar */}
        <div className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between">
          <h2 className="text-2xl font-bold text-slate-900">
            {navItems.find((item) => item.id === currentPage)?.label || 'Dashboard'}
          </h2>
          <div className="flex items-center gap-4">
            <span className="text-sm text-slate-600">Premium features coming soon</span>
          </div>
        </div>

        {/* Page Content */}
        <div className="p-6">{children}</div>
      </main>
    </div>
  );
}
