import { createContext, useContext, useEffect, useState } from 'react';
import type { User } from '../../../drizzle/schema';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  login: (returnPath?: string) => void;
  logout: () => Promise<void>;
  error: string | null;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Check authentication status on mount
  useEffect(() => {
    const checkAuth = async () => {
      try {
        setIsLoading(true);
        // TODO: Call tRPC auth.me procedure to check current user
        // const response = await trpc.auth.me.useQuery();
        // if (response.data) {
        //   setUser(response.data);
        // }
      } catch (err) {
        console.error('Auth check failed:', err);
        setError(err instanceof Error ? err.message : 'Authentication check failed');
      } finally {
        setIsLoading(false);
      }
    };

    checkAuth();
  }, []);

  const login = (returnPath?: string) => {
    // TODO: Redirect to Manus OAuth login
    // const loginUrl = getLoginUrl(returnPath);
    // window.location.href = loginUrl;
    console.log('Login clicked, redirecting to OAuth...');
  };

  const logout = async () => {
    try {
      // TODO: Call tRPC auth.logout procedure
      // await trpc.auth.logout.useMutation();
      setUser(null);
      window.location.href = '/';
    } catch (err) {
      console.error('Logout failed:', err);
      setError(err instanceof Error ? err.message : 'Logout failed');
    }
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isLoading,
        isAuthenticated: !!user,
        login,
        logout,
        error,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}
