import { createTRPCReact } from '@trpc/react-query';
import { httpBatchLink } from '@trpc/client';
import { QueryClient } from '@tanstack/react-query';
import type { AppRouter } from '../../../server/routers';

/**
 * Create tRPC React client
 * This provides type-safe hooks for all backend procedures
 */
export const trpc = createTRPCReact<AppRouter>();

/**
 * Create React Query client for caching and state management
 */
export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5, // 5 minutes
      gcTime: 1000 * 60 * 10, // 10 minutes (formerly cacheTime)
    },
  },
});

/**
 * Create tRPC client with HTTP batch link
 * Batches multiple requests into a single HTTP call for efficiency
 */
export function getTRPCClient() {
  return trpc.createClient({
    links: [
      httpBatchLink({
        url: `${import.meta.env.VITE_API_URL || 'http://localhost:5173'}/api/trpc`,
        // Include credentials for cookie-based authentication
        fetch(url, options) {
          return fetch(url, {
            ...options,
            credentials: 'include',
          });
        },
      }),
    ],
  });
}
