import { ReactNode } from 'react';

interface ButtonProps {
  children: ReactNode;
  onClick?: () => void;
  className?: string;
  disabled?: boolean;
  type?: 'button' | 'submit' | 'reset';
  variant?: 'primary' | 'secondary' | 'success' | 'outline';
  size?: 'sm' | 'md' | 'lg';
}

const variantStyles = {
  primary: 'bg-gradient-to-r from-[#7C3AED] to-[#6D28D9] text-white hover:shadow-lg hover:shadow-purple-500/50 active:scale-95',
  secondary: 'bg-[#1A1F3A] text-white border border-[#374151] hover:border-[#7C3AED] hover:shadow-lg hover:shadow-purple-500/20',
  success: 'bg-[#10B981] text-white hover:bg-[#059669] active:scale-95',
  outline: 'bg-transparent text-white border border-[#374151] hover:border-[#7C3AED] hover:bg-[#7C3AED]/10',
};

const sizeStyles = {
  sm: 'px-3 py-1.5 text-sm',
  md: 'px-4 py-2 text-base',
  lg: 'px-6 py-3 text-lg',
};

export function Button({ 
  children, 
  onClick, 
  className = '', 
  disabled = false, 
  type = 'button',
  variant = 'primary',
  size = 'md',
}: ButtonProps) {
  return (
    <button
      type={type}
      onClick={onClick}
      disabled={disabled}
      className={`rounded-xl font-semibold transition-all duration-300 ${variantStyles[variant]} ${sizeStyles[size]} ${className} ${
        disabled ? 'opacity-50 cursor-not-allowed' : ''
      }`}
    >
      {children}
    </button>
  );
}
